/*
 * home_automation_hub.ino — main sketch for Voice-Controlled Home Automation Hub
 *
 * Element orchestration:
 *   1. Voice Recognition UART Speech Module (LD3320) — keyword → command_id
 *   2. BLE GATT Smartphone App Interface            — manual override write
 *   3. ESP32 WiFi + MQTT IoT Telemetry              — dispatch + broker publish
 *   4. Solid-State Relay Mains Actuator Switching   — 4-channel GPIO drive
 *   5. MQTT QoS-1 Secure Event Logger               — state-change audit log
 */

#include <Arduino.h>
#include <BLEDevice.h>
#include <BLEServer.h>
#include <BLEUtils.h>
#include <BLE2902.h>
#include <WiFi.h>
#include <PubSubClient.h>

// --- WiFi + MQTT ---
const char* SSID        = "HomeNet";
const char* WIFI_PASS   = "changeme";
const char* MQTT_HOST   = "192.168.1.10";
const uint16_t MQTT_PORT = 1883;

// --- SSR GPIO pins (channels 0-3) ---
const uint8_t SSR_PINS[4] = {16, 17, 18, 19};
bool channel_state[4] = {false, false, false, false};

// --- LD3320 UART ---
#define VOICE_SERIAL Serial2
#define VOICE_BAUD   9600

// --- MQTT topics ---
const char* BASE_TOPIC = "home/automation";

// --- BLE UUIDs ---
#define BLE_SERVICE_UUID  "12345678-1234-1234-1234-1234567890ab"
#define BLE_CHAR_UUID     "12345678-1234-1234-1234-1234567890ac"

// --- Voice command map: command_id → {channel, action} ---
// actions: 0=off, 1=on, 2=toggle
struct VoiceCmd { uint8_t channel; uint8_t action; };
const VoiceCmd VOICE_MAP[10] = {
  {0, 1}, {0, 0},   // "light on" / "light off"
  {1, 1}, {1, 0},   // "fan on"   / "fan off"
  {2, 1}, {2, 0},   // "pump on"  / "pump off"
  {3, 1}, {3, 0},   // "channel four on" / "channel four off"
  {0, 2}, {1, 2},   // "toggle light" / "toggle fan"
};

WiFiClient wifiClient;
PubSubClient mqtt(wifiClient);

// --- Apply relay + publish ---
void apply_channel(uint8_t ch, uint8_t action, const char* source) {
  if (ch >= 4) return;
  if (action == 1)      channel_state[ch] = true;
  else if (action == 0) channel_state[ch] = false;
  else                  channel_state[ch] = !channel_state[ch]; // toggle

  digitalWrite(SSR_PINS[ch], channel_state[ch] ? HIGH : LOW);

  // Publish state
  char topic[64], payload[128];
  snprintf(topic,   sizeof(topic),   "%s/%d/state", BASE_TOPIC, ch);
  snprintf(payload, sizeof(payload),
           "{\"channel\":%d,\"state\":%s,\"source\":\"%s\"}",
           ch, channel_state[ch] ? "true" : "false", source);
  mqtt.publish(topic, payload, true);  // retained

  // Publish to audit log
  char log_topic[64];
  snprintf(log_topic, sizeof(log_topic), "%s/log", BASE_TOPIC);
  mqtt.publish(log_topic, payload, false);

  Serial.printf("CH%d → %s  [%s]\n", ch, channel_state[ch] ? "ON" : "OFF", source);
}

// --- BLE callbacks ---
class HubCallbacks : public BLECharacteristicCallbacks {
  void onWrite(BLECharacteristic* c) override {
    uint8_t* data = c->getData();
    size_t   len  = c->getLength();
    if (len >= 2) {
      uint8_t ch     = data[0] & 0x03;
      uint8_t action = data[1];
      apply_channel(ch, action, "ble");
    }
  }
};

void setup_ble() {
  BLEDevice::init("HomeHub");
  BLEServer* server = BLEDevice::createServer();
  BLEService* svc   = server->createService(BLE_SERVICE_UUID);
  BLECharacteristic* chr = svc->createCharacteristic(
    BLE_CHAR_UUID,
    BLECharacteristic::PROPERTY_WRITE
  );
  chr->addDescriptor(new BLE2902());
  chr->setCallbacks(new HubCallbacks());
  svc->start();
  BLEAdvertising* adv = BLEDevice::getAdvertising();
  adv->addServiceUUID(BLE_SERVICE_UUID);
  adv->start();
  Serial.println(F("BLE advertising started."));
}

void mqtt_reconnect() {
  while (!mqtt.connected()) {
    Serial.print(F("Connecting MQTT..."));
    if (mqtt.connect("HomeHub")) {
      Serial.println(F(" connected."));
    } else {
      Serial.printf(" failed rc=%d, retry 5 s\n", mqtt.state());
      delay(5000);
    }
  }
}

void setup() {
  Serial.begin(115200);
  VOICE_SERIAL.begin(VOICE_BAUD, SERIAL_8N1, 13, 14); // RX=13, TX=14

  // SSR pins
  for (uint8_t i = 0; i < 4; i++) {
    pinMode(SSR_PINS[i], OUTPUT);
    digitalWrite(SSR_PINS[i], LOW);  // all off at boot
  }

  // WiFi
  WiFi.begin(SSID, WIFI_PASS);
  while (WiFi.status() != WL_CONNECTED) { delay(500); Serial.print('.'); }
  Serial.printf("\nWiFi OK: %s\n", WiFi.localIP().toString().c_str());

  // MQTT
  mqtt.setServer(MQTT_HOST, MQTT_PORT);
  mqtt_reconnect();

  // BLE
  setup_ble();

  Serial.println(F("Home automation hub ready."));
}

void loop() {
  if (!mqtt.connected()) mqtt_reconnect();
  mqtt.loop();

  // --- 1. Voice recognition polling ---
  if (VOICE_SERIAL.available()) {
    uint8_t cmd_id = (uint8_t)VOICE_SERIAL.read();
    if (cmd_id < 10) {
      VoiceCmd vc = VOICE_MAP[cmd_id];
      apply_channel(vc.channel, vc.action, "voice");
    }
  }

  delay(10);
}
